local Il1="\116\066\033\120\057\095\048\098\102\095\075\051\121\035\081\122\055\126\109\086\114\050\036\112\076"
local IlI=""
local lI1="ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
local l1I={}
for i=1,64 do l1I[string.sub(lI1,i,i)]=i-1 end
local function Ill(s)
	local o,a,b={},0,0
	for i=1,#s do
		local v=l1I[string.sub(s,i,i)]
		if v then
			a=a*64+v b=b+6
			if b>=8 then b=b-8 o[#o+1]=string.char(math.floor(a/(2^b))%256) a=a%(2^b) end
		end
	end
	return table.concat(o)
end
local function llI(x,y)
	local r,p=0,1
	for i=1,8 do local m,n=x%2,y%2 if m~=n then r=r+p end x=(x-m)/2 y=(y-n)/2 p=p*2 end
	return r
end
local I11=Ill(IlI)
local lll={}
local lk=#Il1
for i=1,#I11 do lll[i]=string.char(llI(string.byte(I11,i),string.byte(Il1,(i-1)%lk+1))) end
local Il=loadstring or load
Il(table.concat(lll))()
